const perf = $('Fetch Performance Card').first().json;
const health = $('Fetch Health').first().json;

const alerts = [];
let hasAnomaly = false;

// Check prediction accuracy
const predMade = perf.predictions_made ?? perf.predictionsMade ?? 0;
const predCorrect = perf.predictions_correct ?? perf.predictionsCorrect ?? 0;
const accuracy = predMade > 0 ? (predCorrect / predMade) * 100 : null;

if (accuracy !== null && accuracy < 50) {
  alerts.push(`\u{26A0}\u{FE0F} Prediction accuracy critically low: ${accuracy.toFixed(1)}% (${predCorrect}/${predMade}) in last 24h`);
  hasAnomaly = true;
}

// Check health endpoint
const healthStatus = (health.status ?? '').toLowerCase();
if (healthStatus !== 'ok' && healthStatus !== 'healthy') {
  alerts.push(`\u{1F6A8} Health check failed: status is "${health.status ?? 'unreachable'}"`);
  hasAnomaly = true;
}

// Check for high error rate if available
const apiErrors = health.api_errors ?? health.apiErrors ?? health.errorCount ?? null;
const apiRequests = health.api_requests ?? health.apiRequests ?? health.requestCount ?? null;
if (apiErrors !== null && apiRequests !== null && apiRequests > 0) {
  const errorRate = (apiErrors / apiRequests) * 100;
  if (errorRate > 10) {
    alerts.push(`\u{1F525} High API error rate: ${errorRate.toFixed(1)}% (${apiErrors}/${apiRequests} requests)`);
    hasAnomaly = true;
  }
}

// Check response time if available
const responseTime = health.response_time_ms ?? health.responseTimeMs ?? health.avgResponseTime ?? null;
if (responseTime !== null && responseTime > 5000) {
  alerts.push(`\u{1F422} Slow API response time: ${responseTime}ms (threshold: 5000ms)`);
  hasAnomaly = true;
}

return [{ json: { hasAnomaly, alerts, alertCount: alerts.length, timestamp: new Date().toISOString() } }];

const data = $('Has Anomaly?').first().json;
const alerts = data.alerts;
const timestamp = data.timestamp;
const time = new Date(timestamp).toISOString().replace('T', ' ').substring(0, 19) + ' UTC';

const telegramMessage = `\u{1F6A8} <b>BTC Seer Anomaly Alert</b>
${time}

${alerts.map(a => `• ${a}`).join('
')}

<i>Auto-detected by anomaly monitor (runs every 30 min)</i>`;

const discordMessage = `**\u{1F6A8} BTC Seer Anomaly Alert** (${time})

${alerts.map(a => `- ${a}`).join('
')}

*Auto-detected by anomaly monitor*`;

return [{ json: { telegramMessage, discordMessage } }];

const tgResult = $('Send Alert to Telegram').first().json;
const now = new Date().toISOString();
const tgSuccess = tgResult.ok === true;
console.log(`[${now}] Anomaly Alert — TG: ${tgSuccess ? 'OK' : 'FAIL'} | Discord: sent`);
return [{ json: { logged: true, telegram: tgSuccess, timestamp: now } }];
